// Funcție pentru formatarea telefonului în format internațional
function formatPhoneNumberToInternational(phoneNumber) {
  if (!phoneNumber) return '';

  const cleaned = phoneNumber.replace(/\s+/g, '').replace(/[^\d+]/g, '');

  if (cleaned.startsWith('+')) {
    return cleaned;
  }

  if (cleaned.startsWith('0')) {
    return '+40' + cleaned.substring(1);
  }

  return '+40' + cleaned;
}

// Funcție pentru formatarea datei în formatul specificat (fără probleme de timezone)
function formatDateInRomanian(dateString) {
  if (!dateString) return '';

  try {
    const parts = dateString.split('-');
    if (parts.length === 3) {
      const day = parseInt(parts[2], 10);
      const monthIndex = parseInt(parts[1], 10) - 1;
      const year = parseInt(parts[0], 10);

      const romanianMonths = [
        'Ianuarie', 'Februarie', 'Martie', 'Aprilie', 'Mai', 'Iunie',
        'Iulie', 'August', 'Septembrie', 'Octombrie', 'Noiembrie', 'Decembrie'
      ];

      if (monthIndex < 0 || monthIndex > 11) return '';

      return `${day} ${romanianMonths[monthIndex]} ${year}`;
    }
    return '';
  } catch (error) {
    return '';
  }
}

// Extrage valoare din user_column_data pe baza column_id (pentru Google Ads Lead Forms)
function getUserColumnValue(userColumnData, columnId) {
  if (!userColumnData || !Array.isArray(userColumnData)) return '';

  const column = userColumnData.find(col => col.column_id === columnId);
  return column ? column.string_value : '';
}

// Detectează structura datelor de intrare
function detectDataStructure(item) {
  if (item.body && item.headers) {
    return { body: item.body, headers: item.headers };
  }

  if (item.json && item.json.body && item.json.headers) {
    return { body: item.json.body, headers: item.json.headers };
  }

  if (item.item && item.item.body && item.item.headers) {
    return { body: item.item.body, headers: item.item.headers };
  }

  if (item.data && item.data.body && item.data.headers) {
    return { body: item.data.body, headers: item.data.headers };
  }

  return { body: {}, headers: {} };
}

// Procesează datele indiferent de structura lor
function processItems(items) {
  if (!items || !Array.isArray(items)) {
    if (typeof items === 'object') {
      items = [items];
    } else {
      return [];
    }
  }

  const results = [];

  for (const item of items) {
    if (!item) continue;

    const { body, headers } = detectDataStructure(item);

    // Extrage din user_column_data (Google Ads Lead Forms)
    const nume_din_google = getUserColumnValue(body.user_column_data, 'FULL_NAME');
    const telefon_din_google = getUserColumnValue(body.user_column_data, 'PHONE_NUMBER');

    const result = {
      nume_complet: nume_din_google || body.nume || body.name || '',
      telefon: formatPhoneNumberToInternational(telefon_din_google || body.telefon || body.phone || ''),
      data_programarii_itp: formatDateInRomanian(body.data || body.date || ''),
      gclid: body.gcl_id || body.gclid || '',
      timestamp: body.lead_submit_time || body.timestamp || '',
      ip: headers['x-real-ip'] || headers['x-forwarded-for'] || '',
      user_agent: headers['user-agent'] || ''
    };

    results.push(result);
  }

  return results;
}

return processItems(items);

